59	enum class DisaggRequestKind : int {
60	  kNone = 0,
61	  kPrepareReceive = 1,
62	  kRemoteSend = 2,
63	  kStartGeneration = 3,
64	};
65	
66	/*! \brief Controls the behavior of inference with grammar constraint. */
67	enum class GrammarExecutionMode : int {
68	  /*! \brief If grammar is provided for a request, use the grammar to constrain the output token. */
69	  kConstraint = 0,
70	  /*! \brief If grammar is provided for a request, not only constrain the output, but also use the
71	   * jump-forward decoding to predict the next tokens. This is the default option. */
72	  kJumpForward = 1,
73	};
