850	  /*********************** KV Cache Management  ***********************/
851	
852	  void CreateKVCache(int page_size, int max_num_sequence, int64_t max_total_sequence_length,
853	                     int64_t prefill_chunk_size, int max_history_size,
854	                     int prefix_cache_max_num_recycling_seqs = 0) final {
855	    KVStateKind kv_state_kind = GetMetadata().kv_state_kind;
856	    if (kv_state_kind == KVStateKind::kKVCache) {
857	      Shape max_num_sequence_tuple{max_num_sequence};
858	      Shape max_total_sequence_length_tuple{max_total_sequence_length};
859	      Shape prefill_chunk_size_tuple{prefill_chunk_size};
860	      Shape page_size_tuple{page_size};
861	      Shape support_sliding_window{sliding_window_size_ != -1};
862	      kv_cache_ = ft_.create_kv_cache_func_(max_num_sequence_tuple, max_total_sequence_length_tuple,
863	                                            prefill_chunk_size_tuple, page_size_tuple,
864	                                            support_sliding_window)
865	                      .cast<ObjectRef>();
866	      local_kv_cache_ = ft_.use_disco
867	                            ? kv_cache_.as_or_throw<DRef>()->DebugGetFromRemote(0).cast<ObjectRef>()
868	                            : kv_cache_;
869	    } else if (kv_state_kind == KVStateKind::kRNNState) {
870	      // RNN state needs extra slots for prefix cache recycling sequences.
871	      Shape max_num_sequence_tuple{max_num_sequence + prefix_cache_max_num_recycling_seqs};
872	      Shape max_history_size_tuple = {std::max(max_history_size, 1)};
873	      kv_cache_ = ft_.create_kv_cache_func_(max_num_sequence_tuple, max_history_size_tuple)
874	                      .cast<ObjectRef>();
875	      local_kv_cache_ = ft_.use_disco
876	                            ? kv_cache_.as_or_throw<DRef>()->DebugGetFromRemote(0).cast<ObjectRef>()
877	                            : kv_cache_;
878	    } else if (kv_state_kind == KVStateKind::kHybrid) {
879	      // Hybrid: create both PagedKVCache (for attention layers) and RNNState (for GDN layers).
880	      Shape max_num_sequence_tuple{max_num_sequence};
881	      Shape max_total_sequence_length_tuple{max_total_sequence_length};
882	      Shape prefill_chunk_size_tuple{prefill_chunk_size};
883	      Shape page_size_tuple{page_size};
884	      Shape support_sliding_window{sliding_window_size_ != -1};
885	      kv_cache_ = ft_.create_kv_cache_func_(max_num_sequence_tuple, max_total_sequence_length_tuple,
886	                                            prefill_chunk_size_tuple, page_size_tuple,
887	                                            support_sliding_window)
888	                      .cast<ObjectRef>();
889	      local_kv_cache_ = ft_.use_disco
890	                            ? kv_cache_.as_or_throw<DRef>()->DebugGetFromRemote(0).cast<ObjectRef>()
891	                            : kv_cache_;
892	      // Create RNN state for recurrent layers.
893	      // RNN state needs extra slots for prefix cache recycling sequences that
894	      // coexist with active sequences (e.g., during ForkSequence).
895	      Shape rnn_max_batch{max_num_sequence + prefix_cache_max_num_recycling_seqs};
896	      Shape rnn_max_history{std::max(max_history_size, 1)};
897	      rnn_state_ = ft_.create_rnn_state_func_(rnn_max_batch, rnn_max_history).cast<ObjectRef>();
898	      local_rnn_state_ =
899	          ft_.use_disco ? rnn_state_.as_or_throw<DRef>()->DebugGetFromRemote(0).cast<ObjectRef>()
900	                        : rnn_state_;
901	    } else if (kv_state_kind == KVStateKind::kNone) {
